+    #[test]
+    fn blink_into_bool() {
+        let b: bool = Blink::None.into();
+        assert!(!b);
+        let b: bool = Blink::Slow.into();
+        assert!(b);
+        let b: bool = Blink::Rapid.into();
+        assert!(b);
+    }
